<script>
function validarJSON(){const texto=document.getElementById('json-validar').value.trim();if(!texto){document.getElementById('json-diagnostico').textContent='Nenhum JSON informado';document.getElementById('json-detalhe').textContent='Cole um JSON para validar.';return;}try{JSON.parse(texto);document.getElementById('json-diagnostico').textContent='JSON vï¿½lido';document.getElementById('json-detalhe').textContent='A estrutura foi lida corretamente pelo analisador do navegador.';}catch(error){document.getElementById('json-diagnostico').textContent='JSON invï¿½lido';document.getElementById('json-detalhe').textContent='Hï¿½ erro de sintaxe no conteï¿½do informado. Revise chaves, colchetes, vï¿½rgulas e aspas.';}}
function limparValidadorJSON(){document.getElementById('json-validar').value='';document.getElementById('json-diagnostico').textContent='Aguardando validaï¿½ï¿½o';document.getElementById('json-detalhe').textContent='Cole um JSON e clique no botï¿½o para validar.';}
function copiarValidadorJSON(button){copyToClipboard(document.getElementById('json-diagnostico').textContent+'\n'+document.getElementById('json-detalhe').textContent,button);}
</script>
